import os
import uuid
import subprocess
import tempfile
import io
from pathlib import Path
from flask import Flask, request, send_file, jsonify, make_response
from flask_cors import CORS
from werkzeug.utils import secure_filename

app = Flask(__name__)
CORS(app)
app.config['MAX_CONTENT_LENGTH'] = 50 * 1024 * 1024  # 50MB

ALLOWED_EXTENSIONS = {
    'doc', 'docx', 'odt', 'rtf',
    'xls', 'xlsx', 'ods', 'csv',
    'ppt', 'pptx', 'odp',
    'txt', 'html', 'htm',
    'png', 'jpg', 'jpeg', 'gif', 'bmp', 'webp', 'svg', 'tiff',
    'pdf'
}

def allowed_file(filename):
    return '.' in filename and filename.rsplit('.', 1)[1].lower() in ALLOWED_EXTENSIONS

@app.route('/')
def index():
    import base64
    html = base64.b64decode(b"").decode('utf-8')
    resp = make_response(html)
    resp.headers['Content-Type'] = 'text/html; charset=utf-8'
    return resp

@app.route('/health')
def health():
    return jsonify({'status': 'ok'})

@app.route('/convert', methods=['POST'])
def convert():
    if 'file' not in request.files:
        return jsonify({'error': 'No file provided'}), 400

    file = request.files['file']
    if not file.filename:
        return jsonify({'error': 'No file selected'}), 400

    filename = secure_filename(file.filename)
    if not allowed_file(filename):
        return jsonify({'error': 'File type not supported'}), 400

    ext = filename.rsplit('.', 1)[1].lower()
    original_stem = Path(filename).stem

    # If already PDF, return as-is
    if ext == 'pdf':
        pdf_bytes = file.read()
        return send_file(
            io.BytesIO(pdf_bytes),
            as_attachment=True,
            download_name=original_stem + '.pdf',
            mimetype='application/pdf'
        )

    with tempfile.TemporaryDirectory() as tmpdir:
        uid = str(uuid.uuid4())[:8]
        input_path = os.path.join(tmpdir, f"input_{uid}.{ext}")
        file.save(input_path)

        lo_profile = os.path.join(tmpdir, 'lo_profile')
        os.makedirs(lo_profile, exist_ok=True)

        try:
            result = subprocess.run(
                [
                    'libreoffice',
                    f'-env:UserInstallation=file://{lo_profile}',
                    '--headless',
                    '--norestore',
                    '--nofirststartwizard',
                    '--nologo',
                    '--convert-to', 'pdf',
                    '--outdir', tmpdir,
                    input_path
                ],
                capture_output=True,
                text=True,
                timeout=150,
                env={**os.environ, 'HOME': tmpdir}
            )

            # Find output PDF
            pdfs = [p for p in Path(tmpdir).glob("*.pdf")]
            if not pdfs:
                err = result.stderr[:500] if result.stderr else result.stdout[:500]
                return jsonify({'error': 'Conversion failed: ' + err}), 500

            output_path = str(pdfs[0])
            with open(output_path, 'rb') as f:
                pdf_bytes = f.read()

        except subprocess.TimeoutExpired:
            return jsonify({'error': 'Conversion timed out. Try a smaller file.'}), 500
        except Exception as e:
            return jsonify({'error': str(e)}), 500

    return send_file(
        io.BytesIO(pdf_bytes),
        as_attachment=True,
        download_name=original_stem + '.pdf',
        mimetype='application/pdf'
    )

if __name__ == '__main__':
    port = int(os.environ.get('PORT', 8000))
    app.run(host='0.0.0.0', port=port)
